mapper.select:
SELECT p.id, p.user_id, u.username, p.category, p.title, p.view_count, p.like_count, p.comment_count, p.created_at FROM posts p JOIN users u ON p.user_id = u.id WHERE p.deleted_at IS NULL
AND p.category = #{category}
ORDER BY p.created_at DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE posts
SET title    = #{req.title},
    content  = #{req.content},
    category = #{req.category}
WHERE id = #{id}
  AND deleted_at IS NULL

UPDATE posts
SET deleted_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) > 0
FROM post_likes
WHERE post_id = #{postId}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM post_likes
WHERE post_id = #{postId}
  AND user_id = #{userId}

mapper.update:
UPDATE posts
SET like_count = like_count + 1
WHERE id = #{id}

UPDATE posts
SET like_count = GREATEST(like_count - 1, 0)
WHERE id = #{id}
